#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)b - *(int*)a);
}

int calculateGoodness(char *word) {
    int goodness = 0;
    for (int i = 0; i < strlen(word); i++) {
        goodness += word[i] - 'a' + 1;
    }
    return goodness;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char words[N][100];
        int goodness[N];
        for (int i = 0; i < N; i++) {
            scanf("%s", words[i]);
            goodness[i] = calculateGoodness(words[i]);
        }
        qsort(goodness, N, sizeof(int), compare);
        int totalGoodness = 0;
        for (int i = 0; i < K; i++) {
            totalGoodness += goodness[i];
        }
        printf("%d\n", totalGoodness);
    }
    return 0;
}

