// COMPLETE, COMPILABLE Java code
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static int calculateGoodness(String word) {
        int goodness = 0;
        for (int i = 0; i < word.length(); i++) {
            goodness += word.charAt(i) - 'a' + 1;
        }
        return goodness;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int K = scanner.nextInt();
            String[] words = new String[N];
            int[] goodness = new int[N];
            for (int i = 0; i < N; i++) {
                words[i] = scanner.next();
                goodness[i] = calculateGoodness(words[i]);
            }
            Arrays.sort(goodness);
            int totalGoodness = 0;
            for (int i = N - 1; i >= N - K; i--) {
                totalGoodness += goodness[i];
            }
            System.out.println(totalGoodness);
        }
    }
}

